def _repair_colorado_snap_401_tests(path: Path) -> None:
    cases = _read_yaml_cases(path)
    for case in cases:
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        earned = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_countable_earned_income",
            None,
        )
        unearned = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_countable_unearned_income",
            None,
        )
        shelter = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_allowable_shelter_costs",
            None,
        )
        _remove_keys(
            inputs,
            {
                "us:policies/usda/snap/fy-2026-cola/deductions#input.household_size",
                "us:statutes/7/2014/e/2#input.work_supplementation_earned_income",
                "us:statutes/7/2014/e/6/A#input.dependent_care_deduction",
                "us:statutes/7/2014/e/6/A#input.child_support_deduction",
                "us:statutes/7/2014/e/6/A#input.medical_deduction",
            },
        )
        if earned is not None or unearned is not None or shelter is not None:
            gross = _numeric_test_value(earned) + _numeric_test_value(unearned)
            inputs["us:regulations/7-cfr/273/9#input.snap_gross_monthly_income"] = gross
            inputs["us:regulations/7-cfr/273/9#input.snap_net_income"] = max(
                0,
                gross - _numeric_test_value(shelter),
            )
        outputs = case.get("output")
        if (
            isinstance(outputs, dict)
            and (
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed"
            )
            in outputs
        ):
            group_size_key = (
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size"
            )
            inputs.setdefault(
                group_size_key,
                inputs.get(
                    "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                    "#input.household_size",
                    1,
                ),
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc",
                _snap_fy2026_165_percent_fpl_limit(inputs[group_size_key]),
            )
    _upsert_test_case(
        cases,
        {
            "name": "separate_household_allowed_uses_co_resident_group_size",
            "period": "2026-01",
            "input": {
                "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                "#input.household_size": 1,
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size": 3,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.elderly_disabled_person_unable_to_purchase_and_prepare_meals": True,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.co_resident_gross_income": 3000,
            },
            "output": {
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc": 3665,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed": "holds",
            },
        },
    )
    _upsert_test_case(
        cases,
        {
            "name": "separate_household_denied_when_co_resident_group_income_exceeds_limit",
            "period": "2026-01",
            "input": {
                "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                "#input.household_size": 1,
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size": 3,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.elderly_disabled_person_unable_to_purchase_and_prepare_meals": True,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.co_resident_gross_income": 3666,
            },
            "output": {
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc": 3665,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed": "not_holds",
            },
        },
    )
    _write_yaml_payload(path, cases)


def _snap_fy2026_165_percent_fpl_limit(group_size: object) -> int:
    size = int(_numeric_test_value(group_size))
    table = {
        1: 2152,
        2: 2909,
        3: 3665,
        4: 4421,
        5: 5177,
        6: 5934,
        7: 6690,
        8: 7446,
    }
    return table[max(min(size, 8), 1)] + (max(size - 8, 0) * 757)


