def _repair_section_63_c_cost_of_living_import(
    rules_file: Path,
    *,
    test_files: list[Path],
    path_1_f_3: Path,
) -> list[Path]:
    changed: list[Path] = []
    content = rules_file.read_text()
    section_1_f_3_hash = _sha256_file(path_1_f_3)
    repaired = _ensure_rulespec_import(content, _SECTION_1_F_3_IMPORT)
