def _section_7703_replacement_test_input_block(match: re.Match[str]) -> str:
    indent = match.group("indent")
    not_married_value = match.group("value").strip().lower()
    married = not_married_value not in {"true", "yes", "holds", "1"}
    married_value = "true" if married else "false"
    return (
        f"{indent}us:statutes/26/7703#input.spouse_dies_during_taxable_year: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_married_at_time_of_spouse_death: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_married_at_close_of_taxable_year: {married_value}\n"
        f"{indent}us:statutes/26/7703#input.legally_separated_under_decree_of_divorce_or_separate_maintenance: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_files_separate_return: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_maintains_household_as_home: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_household_cost_fraction_furnished: 0\n"
        f"{indent}us:statutes/26/7703#input.spouse_not_member_of_household_final_month_count: 0\n"
        f"{indent}us:statutes/26/7703#relation.living_apart_child_of_tax_unit: []\n"
    )


def _replace_6012_section_6013_placeholder_test_inputs(content: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*)\?\s+{re.escape(_SECTION_6012_6013_PLACEHOLDER_INPUT)}\n"
        rf"(?P=indent):\s*(?P<value>[^\n]+)\n"
    )
    content = question_key_pattern.sub(
        _section_6013_replacement_test_input_block,
        content,
    )
    scalar_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*){re.escape(_SECTION_6012_6013_PLACEHOLDER_INPUT)}:\s*"
        rf"(?P<value>[^\n]+)\n"
    )
    return scalar_key_pattern.sub(_section_6013_replacement_test_input_block, content)


def _section_6013_replacement_test_input_block(match: re.Match[str]) -> str:
    indent = match.group("indent")
    joint_return_value = (
        "true" if _test_input_value_truthy(match.group("value")) else "false"
    )
    return (
        f"{indent}us:statutes/26/6013/a#input.spouses_have_different_taxable_years: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxable_years_begin_on_same_day: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxable_years_end_on_different_days_because_of_death_of_either_or_both_spouses: false\n"
        f"{indent}us:statutes/26/6013/a#input.surviving_spouse_remarries_before_close_of_surviving_spouse_taxable_year: false\n"
        f"{indent}us:statutes/26/443/a/1#input.taxpayer_changes_annual_accounting_period: false\n"
        f"{indent}us:statutes/26/443/a/1#input.secretary_approves_change_of_annual_accounting_period: false\n"
        f"{indent}us:statutes/26/6013/a#input.death_of_one_spouse_or_both_spouses: false\n"
        f"{indent}us:statutes/26/6013/a#input.joint_return_with_respect_to_decedent_made_by_executor_or_administrator: false\n"
        f"{indent}us:statutes/26/6013/a#input.death_of_one_spouse: false\n"
        f"{indent}us:statutes/26/6013/a#input.joint_return_with_respect_to_both_survivor_and_decedent_made_by_surviving_spouse: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_return_for_taxable_year_made_by_decedent: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_executor_or_administrator_has_been_appointed: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_executor_or_administrator_appointed_before_last_day_prescribed_for_filing_surviving_spouse_return: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxpayers_are_husband_and_wife: {joint_return_value}\n"
        f"{indent}us:statutes/26/6013/a#input.single_return_jointly_of_income_taxes_under_subtitle_a_is_made: {joint_return_value}\n"
        f"{indent}us:statutes/26/6013/a#input.either_spouse_is_nonresident_alien_at_any_time_during_taxable_year: false\n"
    )


def _refresh_proof_import_hashes_for_targets(
    rules_file: Path, repo_path: Path
) -> list[Path]:
    content = rules_file.read_text()
    repaired, repair_count = _repair_proof_import_hashes(
        content,
        target_base=(
            f"{_repo_jurisdiction_prefix(repo_path)}:"
            f"{_relative_rulespec_import_target(rules_file.relative_to(repo_path))}"
        ),
        rules_file=rules_file,
        repo_path=repo_path,
    )
    if repair_count == 0:
        return []
    rules_file.write_text(repaired)
    return [rules_file]


def _replace_test_input_ref(content: str, *, old_ref: str, new_ref: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*)\?\s+{re.escape(old_ref)}\n"
        rf"(?P=indent):\s*(?P<value>[^\n]+)\n"
    )
    content = question_key_pattern.sub(
        lambda match: (
            f"{match.group('indent')}? {new_ref}\n"
            f"{match.group('indent')}: {match.group('value').strip()}\n"
        ),
        content,
    )
    scalar_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*){re.escape(old_ref)}:\s*(?P<value>[^\n]+)\n"
    )
    return scalar_key_pattern.sub(
        lambda match: (
            f"{match.group('indent')}{new_ref}: {match.group('value').strip()}\n"
        ),
        content,
    )


def _remove_test_input_ref(content: str, *, input_ref: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^\s*\?\s+{re.escape(input_ref)}\n\s*:\s*[^\n]+\n"
    )
    content = question_key_pattern.sub("", content)
    scalar_key_pattern = re.compile(rf"(?m)^\s*{re.escape(input_ref)}:\s*[^\n]+\n")
    return scalar_key_pattern.sub("", content)


def _path_differs_from_original(path: Path, original: str | None) -> bool:
    if original is None:
        return path.exists()
    if not path.exists():
        return True
    return path.read_text() != original


def _unique_paths(paths: list[Path]) -> list[Path]:
    unique: list[Path] = []
    seen: set[Path] = set()
    for path in paths:
        resolved = path.resolve()
        if resolved in seen:
            continue
        seen.add(resolved)
        unique.append(path)
    return unique


def _restore_original_files(originals: dict[Path, str | None]) -> None:
    for path, content in originals.items():
        if content is None:
            with contextlib.suppress(FileNotFoundError):
                path.unlink()
        else:
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_text(content)


def cmd_repair_oracle_parameter_tests(args):
    """Apply signed deterministic companion tests for mapped parameter outputs."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    test_file = _rulespec_test_path(rules_file)
    original_test_content = test_file.read_text() if test_file.exists() else ""
    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    repaired_test_cases = _append_oracle_parameter_tests_if_missing(
        rules_file=rules_file,
        test_file=test_file,
        target_base=target_base,
    )
    if not repaired_test_cases:
        print("No oracle parameter test repairs found.")
        return

    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    validation = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=True,
    ).validate(rules_file, skip_reviewers=True)
    if not validation.all_passed:
        test_file.write_text(original_test_content)
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        print("Repair failed validation; restored original test file.")
        for issue in issues:
            print(f"- {issue}")
        sys.exit(1)

    test_failures = _rulespec_companion_test_failures(
        test_file,
        root=repo_path,
        axiom_rules_path=axiom_rules_path,
    )
    if test_failures:
        test_file.write_text(original_test_content)
        print("Repair failed companion tests; restored original test file.")
        for failure in test_failures[:20]:
            case_name = failure.get("case") or "<unknown case>"
            print(f"- {case_name}: {failure.get('message')}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(rules_file.read_text())
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="oracle-parameter-test-v1",
            tool="axiom-encode repair-oracle-parameter-tests",
            citation=target_base,
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=[rules_file, test_file],
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print(
        "Applied oracle parameter test repair to "
        f"{relative_output}: {', '.join(repaired_test_cases)}"
    )
    print(f"manifest={manifest_path}")


def cmd_repair_tax_filing_status_branches(args):
    """Apply signed deterministic repairs for US tax filing-status enum branches."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    test_file = _rulespec_test_path(rules_file)
    original_content = rules_file.read_text()
    repaired_content, repaired_rules = _repair_tax_filing_status_branches(
        original_content
    )
    original_test_content = test_file.read_text() if test_file.exists() else None
    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()

    if repaired_content == original_content:
        print("No tax filing-status branch repairs found.")
        return

    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    repaired_test_content = original_test_content
    repaired_test_rules: list[str] = []
    rules_file.write_text(repaired_content)
    validation_pipeline = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=True,
    )
    validation = validation_pipeline.validate(rules_file, skip_reviewers=True)
    for _attempt in range(8):
        if validation.all_passed:
            break
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        if repaired_test_content is None or not any(
            repair.endswith(":surviving_spouse_to_other_case")
            for repair in repaired_rules
        ):
            break
        next_test_content, test_repairs = (
            _repair_tax_filing_status_branch_test_output_mismatches(
                repaired_test_content,
                issues,
            )
        )
        if not test_repairs:
            break
        repaired_test_content = next_test_content
        repaired_test_rules.extend(test_repairs)
        test_file.write_text(repaired_test_content)
        validation = validation_pipeline.validate(rules_file, skip_reviewers=True)

    if (
        validation.all_passed
        and repaired_test_content is not None
        and repaired_test_rules
        and any(
            repair.endswith(":surviving_spouse_to_other_case")
            for repair in repaired_rules
        )
    ):
        next_test_content, rename_repairs = _rename_tax_filing_status_branch_test_cases(
            repaired_test_content
        )
        if rename_repairs:
            repaired_test_content = next_test_content
            repaired_test_rules.extend(rename_repairs)
            test_file.write_text(repaired_test_content)
            validation = validation_pipeline.validate(
                rules_file,
                skip_reviewers=True,
            )

    if not validation.all_passed:
        rules_file.write_text(original_content)
        if original_test_content is not None:
            test_file.write_text(original_test_content)
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        print("Repair failed validation; restored original file.")
        for issue in issues:
            print(f"- {issue}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="tax-filing-status-branch-v1",
            tool="axiom-encode repair-tax-filing-status-branches",
            citation=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=(
                [rules_file, test_file]
                if repaired_test_content is not None
                and repaired_test_content != original_test_content
                else [rules_file]
            ),
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    repaired_rules.extend(repaired_test_rules)
    print(
        "Applied tax filing-status branch repair to "
        f"{relative_output}: {', '.join(repaired_rules)}"
    )
    print(f"manifest={manifest_path}")


def cmd_repair_tax_status_components(args):
    """Apply signed deterministic repairs for local US tax status component facts."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)
    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    is_section_151_target = relative_output == Path("statutes/26/151.yaml")

    test_file = _rulespec_test_path(rules_file)
    original_content = rules_file.read_text()
    original_test_content = test_file.read_text() if test_file.exists() else None
    repaired_content, repaired_components = _repair_tax_status_component_local_inputs(
        original_content
    )
    repaired_content, renamed_temporal_facts = _repair_section_151_temporal_fact_names(
        repaired_content
    )
    repaired_content, deferred_151_phaseout = _repair_section_151_68b_phaseout_deferral(
        repaired_content
    )
    (
        repaired_content,
        repaired_151_imports,
        generated_151_import_files,
    ) = _repair_section_151_imports(repaired_content, repo_path=repo_path)
    (
        repaired_content,
        repaired_151_exclusion_imports,
        generated_151_exclusion_files,
    ) = _repair_section_151_exclusion_dependencies(
        repaired_content, repo_path=repo_path
    )
    (
        repaired_content,
        repaired_151_dependency_imports,
        generated_151_dependency_files,
    ) = _repair_section_151_152_dependency(repaired_content, repo_path=repo_path)
    repaired_content, repaired_24_child_dependency_imports = (
        _repair_section_24_child_dependency_imports(
            repaired_content, repo_path=repo_path
        )
    )
    (
        repaired_content,
        repaired_24_7527a_imports,
        generated_24_7527a_files,
    ) = _repair_section_24_7527a_dependency(repaired_content, repo_path=repo_path)
    repaired_test_content, removed_test_refs = _remove_tax_status_component_test_inputs(
        original_test_content,
        repaired_components=repaired_components,
    )
    repaired_test_content, renamed_temporal_test_refs = (
        _repair_section_151_temporal_test_input_names(repaired_test_content)
    )
    repaired_test_content, repaired_151_test_refs = _repair_section_151_test_inputs(
        repaired_test_content
    )
    repaired_test_content, repaired_exclusion_test_refs = (
        _repair_exclusion_dependency_test_inputs(
            repaired_test_content,
            target_base=target_base,
        )
    )
    repaired_test_content, repaired_24_child_test_refs = (
        _repair_section_24_child_dependency_test_inputs(repaired_test_content)
    )
    repaired_test_content, repaired_24_7527a_test_refs = (
        _repair_section_24_7527a_test_inputs(repaired_test_content)
    )
    if is_section_151_target:
        extra_file_contents, repaired_related_151_test_refs = (
            _repair_section_151_related_test_inputs(
                repo_path=repo_path,
                target_test_file=test_file,
                repaired_components=repaired_components,
            )
        )
    else:
        extra_file_contents, repaired_related_151_test_refs = {}, []
    related_151_test_files = (
        _section_151_related_test_files(
            repo_path=repo_path,
            target_test_file=test_file,
        )
        if is_section_151_target
        else []
    )
    generated_dependency_files = {
        **generated_151_import_files,
        **generated_151_dependency_files,
        **generated_151_exclusion_files,
        **generated_24_7527a_files,
    }
    extra_file_contents.update(generated_151_import_files)
    extra_file_contents.update(generated_151_dependency_files)
    extra_file_contents.update(generated_151_exclusion_files)
    extra_file_contents.update(generated_24_7527a_files)
    if (
        repaired_content == original_content
        and not removed_test_refs
        and not renamed_temporal_test_refs
        and not deferred_151_phaseout
        and not repaired_151_imports
        and not repaired_151_exclusion_imports
        and not repaired_151_dependency_imports
        and not repaired_24_child_dependency_imports
        and not repaired_24_7527a_imports
        and not repaired_151_test_refs
        and not repaired_exclusion_test_refs
        and not repaired_24_child_test_refs
        and not repaired_24_7527a_test_refs
        and not repaired_related_151_test_refs
        and not extra_file_contents
    ):
        print("No tax status component repairs found.")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)
    _ensure_generated_dependency_files_safe(
        repo_path,
        generated_files=generated_dependency_files,
    )
    guard_files = [rules_file]
    if (
        repaired_test_content is not None
        and repaired_test_content != original_test_content
    ):
        guard_files.append(test_file)
    guard_files.extend(
        path for path in extra_file_contents if path not in generated_dependency_files
    )
    _ensure_no_unmanifested_preexisting_rulespec_changes(
        repo_path,
        [(relative_output, _unique_paths(guard_files))],
    )
    original_extra_contents = {
        path: (path.read_text() if path.exists() else None)
        for path in extra_file_contents
    }
    preexisting_test_targets = [test_file] if test_file.exists() else []
    preexisting_test_targets.extend(
        path
        for path in extra_file_contents
        if path.name.endswith(".test.yaml") and path.exists()
    )
    preexisting_test_targets.extend(
        path for path in related_151_test_files if path.exists()
    )
    preexisting_test_targets = _unique_paths(preexisting_test_targets)
    preexisting_test_issues = set(
        _companion_test_issues(
            test_files=preexisting_test_targets,
            repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
        )
    )

    rules_file.write_text(repaired_content)
    if (
        repaired_test_content is not None
        and repaired_test_content != original_test_content
    ):
        test_file.write_text(repaired_test_content)
    for path, content in extra_file_contents.items():
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content)

    validation_targets = [rules_file]
    validation_targets.extend(
        path
        for path in extra_file_contents
        if path.suffix in {".yaml", ".yml"} and not path.name.endswith(".test.yaml")
    )
    validation_targets = _unique_paths(validation_targets)
    validation_issues: list[str] = []
    validation = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=True,
    )
    for validation_target in validation_targets:
        result = validation.validate(validation_target, skip_reviewers=True)
        if result.all_passed:
            continue
        validation_issues.extend(
            item.error for item in result.results.values() if item.error
        )
    if validation_issues:
        rules_file.write_text(original_content)
        if original_test_content is not None:
            test_file.write_text(original_test_content)
        _restore_original_files(original_extra_contents)
        print("Repair failed validation; restored original RuleSpec file.")
        for issue in validation_issues:
            print(f"- {issue}")
        sys.exit(1)

    test_targets = [test_file]
    test_targets.extend(
        path for path in extra_file_contents if path.name.endswith(".test.yaml")
    )
    test_targets.extend(related_151_test_files)
    test_targets = [path for path in _unique_paths(test_targets) if path.exists()]
    test_issues = _companion_test_issues(
        test_files=test_targets,
        repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
    )
    new_test_issues = [
        issue for issue in test_issues if issue not in preexisting_test_issues
    ]
    if new_test_issues:
        rules_file.write_text(original_content)
        if original_test_content is not None:
            test_file.write_text(original_test_content)
        _restore_original_files(original_extra_contents)
        print("Repair failed companion tests; restored original RuleSpec file.")
        for issue in new_test_issues:
            print(f"- {issue}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(rules_file.read_text())
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="tax-status-component-v1",
            tool="axiom-encode repair-tax-status-components",
            citation=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        applied_files = [rules_file]
        if test_file.exists():
            applied_files.append(test_file)
        applied_files.extend(extra_file_contents)
        applied_files.extend(related_151_test_files)
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=applied_files,
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    repairs = [
        f"{identifier}->{expression}"
        for identifier, expression in sorted(repaired_components.items())
    ]
    repairs.extend(removed_test_refs)
    repairs.extend(renamed_temporal_facts)
    repairs.extend(renamed_temporal_test_refs)
    repairs.extend(deferred_151_phaseout)
    repairs.extend(repaired_151_imports)
    repairs.extend(repaired_151_exclusion_imports)
    repairs.extend(repaired_151_dependency_imports)
    repairs.extend(repaired_24_child_dependency_imports)
    repairs.extend(repaired_24_7527a_imports)
    repairs.extend(repaired_151_test_refs)
    repairs.extend(repaired_exclusion_test_refs)
    repairs.extend(repaired_24_child_test_refs)
    repairs.extend(repaired_24_7527a_test_refs)
    repairs.extend(repaired_related_151_test_refs)
    print(
        "Applied tax status component repair to "
        f"{relative_output}: {', '.join(repairs)}"
    )
    print(f"manifest={manifest_path}")


def cmd_repair_missing_source_proofs(args):
    """Apply signed deterministic repairs for missing source proof atoms."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    original_content = rules_file.read_text()
    repaired_content, repaired_rules = _repair_missing_source_proof_atoms(
        original_content
    )
    if repaired_content == original_content:
        print("No missing source proof repairs found.")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    rules_file.write_text(repaired_content)
    validation = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=True,
    ).validate(rules_file, skip_reviewers=True)
    if not validation.all_passed:
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        if _only_pending_tax_filing_status_branch_issues(
            issues
        ) or _only_pending_nonnegative_amount_reduction_issues(issues):
            print(
                "Applied missing source proof repair with pending deterministic "
                "validation repair still required."
            )
        else:
            rules_file.write_text(original_content)
            print("Repair failed validation; restored original file.")
            for issue in issues:
                print(f"- {issue}")
            sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="source-proof-atom-v1",
            tool="axiom-encode repair-missing-source-proofs",
            citation=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=[rules_file],
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print(
        "Applied missing source proof repair to "
        f"{relative_output}: {', '.join(repaired_rules)}"
    )
    print(f"manifest={manifest_path}")


def _repair_tax_filing_status_branches(content: str) -> tuple[str, list[str]]:
    if (
        "surviving spouse" not in content.lower()
        and "qualifying widow" not in content.lower()
        and "any other case" not in content.lower()
    ):
        return content, []

    repaired: list[str] = []
    repaired_rules: list[str] = []
    fallback_mode = (
        "surviving_joint"
        if (
            "surviving spouse" in content.lower()
            or "qualifying widow" in content.lower()
        )
        else None
    )
    fallback_needs_other_case = "any other case" in content.lower()
    repair_modes = _tax_filing_status_branch_repair_modes(content)
    content, summary_repairs = _repair_tax_filing_status_branch_summary(
        content,
        has_joint_only_other_case=any(
            mode == "joint_only_other" for mode in repair_modes.values()
        ),
    )
    current_rule_name: str | None = None
    index = 0
    lines = content.splitlines(keepends=True)

    while index < len(lines):
        line = lines[index]
        stripped = line.strip()
        if stripped.startswith("- name: "):
            current_rule_name = stripped.removeprefix("- name: ").strip()
        if stripped == "match filing_status:":
            match_block = [line]
            index += 1
            while index < len(lines):
                block_line = lines[index]
                block_stripped = block_line.strip()
                if block_stripped and "=>" not in block_stripped:
                    break
                match_block.append(block_line)
                index += 1
            repaired_block, block_repairs = _repair_tax_filing_status_match_block(
                match_block,
                repair_mode=repair_modes.get(current_rule_name or "") or fallback_mode,
                needs_other_case=repair_modes.get(current_rule_name or "")
                == "joint_only_other"
                or fallback_needs_other_case,
            )
            repaired.extend(repaired_block)
            repaired_rules.extend(
                f"{current_rule_name or '<unknown>'}:{repair}"
                for repair in block_repairs
            )
            continue

        repaired.append(line)
        index += 1

    return "".join(repaired), [*summary_repairs, *repaired_rules]


def _repair_tax_filing_status_branch_summary(
    content: str, *, has_joint_only_other_case: bool
) -> tuple[str, list[str]]:
    if not has_joint_only_other_case:
        return content, []

    summary_end_candidates = [
        position
        for position in (
            content.find("\n  source_verification:"),
            content.find("\nrules:"),
        )
        if position != -1
    ]
    if not summary_end_candidates:
        return content, []

    summary_end = min(summary_end_candidates)
    summary = content[:summary_end]
    rest = content[summary_end:]
    repaired = summary
    repairs: list[str] = []

    enum_repaired = _FILING_STATUS_SUMMARY_JOINT_SURVIVING_PATTERN.sub(
        _repair_tax_filing_status_branch_summary_enum_match,
        repaired,
    )
    if enum_repaired != repaired:
        repaired = enum_repaired
        repairs.append("summary:surviving_spouse_to_other_case")

    phrase_repaired = _replace_tax_filing_status_summary_phrase(
        repaired,
        "joint / surviving spouse",
        "joint return",
    )
    phrase_repaired = _replace_tax_filing_status_summary_phrase(
        phrase_repaired,
        "joint or surviving spouse",
        "joint return",
    )
    for old, new in [
        (
            "$250,000 for a joint return or surviving\n"
            "    spouse, one-half of that amount for a married individual filing\n"
            "    separately, and $200,000 in any other case.",
            "$250,000 for a joint return, one-half of that amount for a married\n"
            "    individual filing separately, and $200,000 in any other case.",
        ),
        (
            "$250,000 for a joint return or surviving\n    spouse, ",
            "$250,000 for a joint return, ",
        ),
        (
            "$250,000 for a joint return or surviving spouse, ",
            "$250,000 for a joint return, ",
        ),
        (
            "$250,000 for a joint return or surviving spouse",
            "$250,000 for a joint return",
        ),
    ]:
        phrase_repaired = phrase_repaired.replace(old, new)
    if phrase_repaired != repaired:
        repaired = phrase_repaired
        repairs.append("summary:surviving_spouse_to_other_case")

    if repaired == summary:
        return content, []
    return repaired + rest, list(dict.fromkeys(repairs))


_FILING_STATUS_SUMMARY_JOINT_SURVIVING_PATTERN = re.compile(
    r"(?m)^(?P<indent>[ \t]*)1\s*=\s*joint\s*/\s*surviving spouse"
    r"(?P<newline>\r?\n)(?P=indent)2\s*=\s*married filing separately"
    r"(?P<line2_tail>[^\r\n]*)"
    r"(?:(?P=newline)(?P=indent)3\s*=\s*head of household"
    r"(?P<line3_tail>[^\r\n]*))?"
)
_FILING_STATUS_SUMMARY_ENUM_LINE_PATTERN = re.compile(r"^[ \t]*\d+\s*=")


def _repair_tax_filing_status_branch_summary_enum_match(
    match: re.Match[str],
) -> str:
    indent = match.group("indent")
    newline = match.group("newline")
    lines = [
        f"{indent}1 = joint",
        f"{indent}2 = married filing separately{match.group('line2_tail') or ''}",
    ]
    line3_tail = match.group("line3_tail")
    if line3_tail is not None:
        lines.append(f"{indent}3 = head of household{line3_tail}")
    lines.append(f"{indent}4 = surviving spouse / qualifying widow(er)")
    return newline.join(lines)


def _replace_tax_filing_status_summary_phrase(text: str, old: str, new: str) -> str:
    lines: list[str] = []
    for line in text.splitlines(keepends=True):
        if _FILING_STATUS_SUMMARY_ENUM_LINE_PATTERN.match(line):
            lines.append(line)
            continue
        lines.append(line.replace(old, new))
    return "".join(lines)


def _tax_filing_status_branch_repair_modes(content: str) -> dict[str, str]:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return {}
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return {}

    module_source_text = (
        _extract_source_verification_text(content)
        or extract_embedded_source_text(content)
        or content
    )
    modes: dict[str, str] = {}
    for name, kind, formula, source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived" or "filing_status" not in formula:
            continue
        source_context = _filing_status_rule_source_context(
            content=content,
            module_source_text=module_source_text,
            rule=rule,
            source=source,
        )
        if _US_TAX_JOINT_SURVIVING_SPOUSE_GROUP_TEXT_PATTERN.search(source_context):
            modes[name] = "surviving_joint"
        elif _US_TAX_JOINT_ONLY_ANY_OTHER_CASE_TEXT_PATTERN.search(source_context):
            modes[name] = "joint_only_other"
    return modes


_TEST_OUTPUT_MISMATCH_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` output `(?P<output>[^`]+)` "
    r"expected [^,]+, got "
    r"(?:(?P<kind>integer|decimal|float|number|boolean|string|bool|text) )?"
    r"(?P<actual>.+?)\.$"
)


def _repair_tax_filing_status_branch_test_output_mismatches(
    test_content: str,
    issues: list[str],
) -> tuple[str, list[str]]:
    try:
        payload = yaml.safe_load(test_content)
    except (yaml.YAMLError, ValueError):
        return test_content, []
    if not isinstance(payload, list):
        return test_content, []

    repairs: list[str] = []
    cases_by_name = {
        str(case.get("name") or ""): case for case in payload if isinstance(case, dict)
    }
    for issue in issues:
        match = _TEST_OUTPUT_MISMATCH_PATTERN.search(issue)
        if match is None:
            continue
        case_name = match.group("case")
        output_name = match.group("output")
        case = cases_by_name.get(case_name)
        if not isinstance(case, dict) or not _test_case_has_filing_status(case, 4):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict) or output_name not in outputs:
            continue
        actual_value = _parse_validator_actual_output_value(
            match.group("actual"),
            kind=match.group("kind"),
        )
        if outputs[output_name] == actual_value:
            continue
        outputs[output_name] = actual_value
        repairs.append(f"test:{case_name}:{output_name}")

    if not repairs:
        return test_content, []
    return yaml.safe_dump(payload, sort_keys=False), repairs


def _rename_tax_filing_status_branch_test_cases(
    test_content: str,
) -> tuple[str, list[str]]:
    try:
        payload = yaml.safe_load(test_content)
    except (yaml.YAMLError, ValueError):
        return test_content, []
    if not isinstance(payload, list):
        return test_content, []

    repairs: list[str] = []
    for case in payload:
        if not isinstance(case, dict) or not _test_case_has_filing_status(case, 4):
            continue
        case_name = str(case.get("name") or "")
        if (
            "surviving_spouse" not in case_name and "qualifying_widow" not in case_name
        ) or "joint_threshold" not in case_name:
            continue
        new_case_name = case_name.replace(
            "uses_joint_threshold",
            "uses_other_threshold",
        ).replace("joint_threshold", "other_threshold")
        if new_case_name == case_name:
            continue
        case["name"] = new_case_name
        repairs.append(f"test:{case_name}->{new_case_name}")

    if not repairs:
        return test_content, []
    return yaml.safe_dump(payload, sort_keys=False), repairs


def _test_case_has_filing_status(case: dict[str, Any], value: int) -> bool:
    inputs = case.get("input")
    if not isinstance(inputs, dict):
        return False
    for key, input_value in inputs.items():
        if not isinstance(key, str) or not key.endswith("#input.filing_status"):
            continue
        if str(input_value).strip() == str(value):
            return True
    return False


def _parse_validator_actual_output_value(
    raw_value: str, *, kind: str | None = None
) -> Any:
    value_text = raw_value.strip()
    normalized_kind = (kind or "").lower()
    if normalized_kind in {"string", "text"}:
        return value_text
    with contextlib.suppress(yaml.YAMLError):
        return yaml.safe_load(value_text)
    return value_text


def _repair_tax_filing_status_match_block(
    block: list[str],
    *,
    repair_mode: str | None,
    needs_other_case: bool,
) -> tuple[list[str], list[str]]:
    arms: dict[int, tuple[str, str]] = {}
    for line in block:
        arm_match = re.match(r"(\s*)(\d+)\s*=>\s*(.+)$", line.rstrip("\n"))
        if arm_match is None:
            continue
        indent, code, expression = arm_match.groups()
        arms[int(code)] = (indent, expression)

    other_case_expression = None
    if 0 in arms:
        other_case_expression = arms[0][1]
    elif 3 in arms:
        other_case_expression = arms[3][1]

    should_add_surviving_spouse = (
        repair_mode == "surviving_joint" and 1 in arms and 4 not in arms
    )
    should_add_surviving_spouse_to_other = (
        repair_mode == "joint_only_other"
        and 1 in arms
        and 4 not in arms
        and other_case_expression is not None
    )
    should_route_surviving_spouse_to_other = (
        repair_mode == "joint_only_other"
        and 1 in arms
        and 4 in arms
        and other_case_expression is not None
        and arms[4][1].strip() == arms[1][1].strip()
    )
    should_add_other_case = needs_other_case and 0 in arms and 3 not in arms

    repaired: list[str] = []
    repairs: list[str] = []
    for line in block:
        arm_match = re.match(r"(\s*)(\d+)\s*=>\s*(.+)$", line.rstrip("\n"))
        if arm_match is not None:
            indent, code, expression = arm_match.groups()
            if code == "4" and should_route_surviving_spouse_to_other:
                repaired.append(f"{indent}4 => {other_case_expression}\n")
                repairs.append("surviving_spouse_to_other_case")
                continue

        repaired.append(line)
        if arm_match is None:
            continue
        indent, code, expression = arm_match.groups()
        if code == "1" and should_add_surviving_spouse:
            repaired.append(f"{indent}4 => {expression}\n")
            repairs.append("surviving_spouse")
        if code == "1" and should_add_surviving_spouse_to_other:
            repaired.append(f"{indent}4 => {other_case_expression}\n")
            repairs.append("surviving_spouse_to_other_case")
        if code == "0" and should_add_other_case:
            repaired.append(f"{indent}3 => {expression}\n")
            repairs.append("other_case")

    return repaired, repairs


